import { nativeImage } from 'electron';

const MAX_WIDTH = 240;
const MAX_HEIGHT = 360;
const JPEG_QUALITY = 82;

const PLACEHOLDER_THUMBNAIL = Buffer.from(
  '',
  'base64'
);

export function generateThumbnail(source: Buffer | null | undefined): Buffer {
  if (!source || source.length === 0) return PLACEHOLDER_THUMBNAIL;

  try {
    const image = nativeImage.createFromBuffer(source);
    if (image.isEmpty()) return PLACEHOLDER_THUMBNAIL;

    const size = image.getSize();
    if (size.width <= 0 || size.height <= 0) return PLACEHOLDER_THUMBNAIL;

    const scale = Math.min(MAX_WIDTH / size.width, MAX_HEIGHT / size.height, 1);
    const resized = image.resize({
      width: Math.max(1, Math.round(size.width * scale)),
      height: Math.max(1, Math.round(size.height * scale)),
      quality: 'good',
    });

    const encoded = resized.toJPEG(JPEG_QUALITY);
    return encoded.length > 0 ? encoded : PLACEHOLDER_THUMBNAIL;
  } catch {
    return PLACEHOLDER_THUMBNAIL;
  }
}

